public class Variables {
  public static void main(String[] args) {
    name = "Alice";
    age = 25;
    height = 5.6;
    isStudent = true;

    System.out.println("Name: " + name);
    System.out.println("Age: " + age);
    System.out.println("Height: " + height);
    System.out.println("Student: " + isStudent);
  }
}
